    "iyal": {
      "ta": "அரசியல்",
      "en": "Royalty"
    },
    "adhigaram": {
      "number": 44,
      "ta": "குற்றங்கடிதல்",
      "en": "The Correction of Faults"
    },
    "kural": {
      "line1": "தன்குற்றம் நீக்கிப் பிறர்குற்றங் காண்கிற்பின்",
      "line2": "என்குற்ற மாகும் இறைக்கு?"
    },
    "meaning": {
      "ta": "முன்னே தன் குற்றத்தைக் கண்டு நீக்கி பிறகு பிறருடையக் குற்றத்தை ஆராயவல்லவனானால், தலைவனுக்கு என்ன குற்றமாகும்.",
      "en": "What fault will remain in the king who has put away his own evils, and looks after the evils of others"
    },
    "couplet_en": "Faultless the king who first his own faults cures, and thenPermits himself to scan faults of other men",
    "transliteration": "Thankutram Neekkip Pirarkutrang Kaankirpin Enkutra Maakum Iraikku?",
