    "adhigaram": {
      "number": 71,
      "ta": "குறிப்பறிதல்",
      "en": "The Knowledge of Indications"
    },
    "kural": {
      "line1": "பகைமையும் கேண்மையும் கண்ணுரைக்கும் கண்ணின்",
      "line2": "வகைமை உணர்வார்ப் பெறின்."
    },
    "meaning": {
      "ta": "கண்பார்வையின் வேறுபாடுகளை உணரவல்லவரைப் பெற்றால்( ஒருவனுடைய மனதில் உள்ள) கையையும் நட்பையும் அவனுடைய கண்களே சொல்லி விடும்.",
      "en": "If a king gets ministers who can read the movements of the eye, the eyes (of foreign kings) will (themselves) reveal (to him) their hatred or friendship"
    },
    "couplet_en": "The eye speaks out the hate or friendly soul of man; To those who know the eye's swift varying moods to scan",
    "transliteration": "Pakaimaiyum Kenmaiyum Kannuraikkum Kannin Vakaimai Unarvaarp Perin",
