    "adhigaram": {
      "number": 71,
      "ta": "குறிப்பறிதல்",
      "en": "The Knowledge of Indications"
    },
    "kural": {
      "line1": "நுண்ணியம் என்பார் அளக்குங்கோல் காணுங்கால்",
      "line2": "கண்ணல்லது இல்லை பிற."
    },
    "meaning": {
      "ta": "யாம் நுட்பமான அறிவுடையேம் என்று பிறர் கருத்தை அறிபவரின் அளக்குங்கோல், ஆராய்ந்து பார்த்தால் அவனுடையக் கண்களே அல்லாமல் வேறு இல்லை.",
      "en": "The measuring-rod of those (ministers) who say \"we are acute\" will on inquiry be found to be their (own) eyes and nothing else"
    },
    "couplet_en": "The men of keen discerning soul no other test apply(When you their secret ask) than man's revealing eye",
    "transliteration": "Nunniyam Enpaar Alakkungol Kaanungaal Kannalladhu Illai Pira",
