    "adhigaram": {
      "number": 76,
      "ta": "பொருள் செயல்வகை",
      "en": "Way of Accumulating Wealth"
    },
    "kural": {
      "line1": "அறன்ஈனும் இன்பமும் ஈனும் திறனறிந்து",
      "line2": "தீதின்றி வந்த பொருள்."
    },
    "meaning": {
      "ta": "சேர்க்கும் திறம் அறிந்து தீமை ஒன்றும் இல்லாமல், சேர்க்கப் பட்டுவந்த பொருள் ஒருவனுக்கு அறத்தையும் கொடுக்கும் இன்பத்தையும் கொடுக்கும்.",
      "en": "The wealth acquired with a knowledge of the proper means and without foul practices will yield virtue and happiness"
    },
    "couplet_en": "Their wealth, who blameless means can use aright,Is source of virtue and of choice delight",
    "transliteration": "Araneenum Inpamum Eenum Thiranarindhu Theedhindri Vandha Porul",
