    "adhigaram": {
      "number": 77,
      "ta": "படை மாட்சி",
      "en": "The Excellence of an Army"
    },
    "kural": {
      "line1": "அழிவின்றி அறைபோகா தாகி வழிவந்த",
      "line2": "வன்க ணதுவே படை."
    },
    "meaning": {
      "ta": "(போர் முனையில்) அழிவு இல்லாததாய்(பகைவருடைய) வஞ்சனைக்கு இரையாகாததாய், தொன்று தொட்டுவந்த அஞ்சாமை உடையதே படையாகும்.",
      "en": "That indeed is an army which has stood firm of old without suffering destruction or deserting (to the enemy)"
    },
    "couplet_en": "That is a host, by no defeats, by no desertions shamed,For old hereditary courage famed",
    "transliteration": "Azhivindri Araipokaa Thaaki Vazhivandha Vanka Nadhuve Patai",
