    "pal": {
      "ta": "பொருட்பால்",
      "en": "Wealth"
    },
    "iyal": {
      "ta": "குடியியல்",
      "en": "Miscellaneous"
    },
    "adhigaram": {
      "number": 104,
      "ta": "உழவு",
      "en": "Farming"
    },
    "kural": {
      "line1": "இரவார் இரப்பார்க்கொன்று ஈவர் கரவாது",
      "line2": "கைசெய்தூண் மாலை யவர்."
    },
    "meaning": {
      "ta": "கையால் தொழில் செய்து உணவு தேடி உண்ணும் இயல்புடைய தொழிலாளர், பிறரிடம் சென்று இரக்கமாட்டார், தம்மிடம் இரந்தவர்க்கு ஒளிக்காமல் ஒரு பொருள் ஈவார்.",
      "en": "Those whose nature is to live by manual labour will never beg but give something to those who beg"
    },
    "couplet_en": "They nothing ask from others, but to askers give,Who raise with their own hands the food on which they live",
    "transliteration": "Iravaar Irappaarkkondru Eevar Karavaadhu Kaiseydhoon Maalai Yavar",
